INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RC2j_L3_B', 'RC2j', 3, 'B', 'Detecting Broken Rhythm', 'Printed poem', 'Listen: ''Twinkle twinkle little star, how I wonder what you are up in the sky so very high.'' Did I read that with the right beat, or did I mess up the rhythm?', 'Child identifies that running the lines together ruined the song''s meter/rhythm.', 'If they think it''s fine, sing it correctly and ask them to compare.', 'Why does rhythm matter in a poem or song?', '{"default":{"poem":"Twinkle Twinkle"},"ug":{"poem":"Twinkle Twinkle"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RC2j_L3_C', 'RC2j', 3, 'C', 'Identifying Sensory Language', 'Printed poem', 'Poems often use words that paint a picture in your mind. Look at this poem. Find one phrase that helps you ''see'' or ''hear'' what the poet is talking about.', 'Child locates descriptive, sensory language within the poetic text.', 'If they struggle, ask: ''What words tell us what color it is? Or how loud it is?''', 'How do those words help make the poem interesting?', '{"default":{"theme":"the wind"},"ug":{"theme":"the rain on a tin roof"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RC2j_L4_A', 'RC2j', 4, 'A', 'Writing an Acrostic Poem', 'Paper, Pencil', 'Write your name downwards on the paper. Now write a describing word or short phrase that starts with each letter of your name. This is an acrostic poem!', 'Child successfully formats and writes an acrostic poem based on their name.', 'If they struggle to find words, help them brainstorm traits or things they like.', 'Does an acrostic poem have to rhyme? (No).', '{"default":{"format":"acrostic"},"ug":{"format":"acrostic"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RC2j_L4_B', 'RC2j', 4, 'B', 'Converting Prose to Poetry', 'A printed prose sentence, Paper, Pencil', 'Here is a normal sentence: ''The big green frog jumped into the cold water with a splash.'' Turn this into a short poem by chopping it into lines and maybe adding a rhyme.', 'Child restructures the prose into a poetic format (e.g., adding line breaks, altering words).', 'If they just copy it, show them how to break it: ''The big green frog / jumped off the log...''', 'How does your poem look and sound different from the normal sentence?', '{"default":{"theme":"frog in water"},"ug":{"theme":"frog in water"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RC2j_L4_C', 'RC2j', 4, 'C', 'Reciting from Memory', 'A short poem practiced previously', 'You have been practicing this short poem. Put the paper away and recite it from memory. Try to use expression and rhythm!', 'Child recites the poem accurately with appropriate prosody.', 'If they forget, prompt them with the first word of the line.', 'Is it easier to memorize a poem or a normal story paragraph? Why?', '{"default":{"task":"memorization"},"ug":{"task":"memorization"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RC2j_L4_M', 'RC2j', 4, 'M', 'Creating a Choral Chant', 'Paper, Pencil', 'Think of a chore we do at home (like sweeping or washing dishes). Create a short, two-line rhythmic chant we could say while doing that chore to make it fun. Teach it to me.', 'Child creates a rhythmic, functional chant and demonstrates it with steady beat.', 'Do not correct during the task. The goal is applying rhythm to language creatively.', 'Does your chant match the rhythm of the work we are doing?', '{"default":{"chore":"sweeping"},"ug":{"chore":"sweeping or washing plates"}}', 0);

